axs[0].plot(teta, sigma_dBteta, color='orange', linestyle='-', linewidth=1, label='GreenTensor')
axs[0].set_title("Бистатический ЭПР (дБ) | E theta | VV-pol")
axs[0].legend(loc='upper right')

# График справа
axs[1].plot(teta, sigma_dBphi, color='blue', linestyle='-', linewidth=1, label='GreenTensor')
axs[1].set_title("Бистатический ЭПР (дБ) | E phi | HH-pol")
axs[1].legend(loc='upper right')

